function areAnagrams(s1, s2) {
  if (s1.length !== s2.length) return false;

  const count = {};

  for (const char of s1) {
    count[char] = (count[char] || 0) + 1;
  }

  for (const char of s2) {
    if (!count[char]) return false;
    count[char]--;
  }

  return true;
}
